// 교육용 빅뱅 시뮬레이션 - 2D Canvas 기반
// 이미지 형식처럼 4단계를 모두 표시

export function createEducationalBigBangCanvas() {
  const canvas = document.createElement('canvas');
  canvas.width = 1200;
  canvas.height = 800;
  const ctx = canvas.getContext('2d');

  // 배경
  ctx.fillStyle = '#000000';
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  // 단계별 위치
  const stages = [
    { x: 200, y: 200, name: '쿼크-글루온\n플라즈마', time: '10⁻¹² 초' },
    { x: 600, y: 200, name: '양성자/중성자\n형성', time: '10⁻⁶ 초' },
    { x: 200, y: 550, name: '핵융합\n원자핵 형성', time: '1-3 분' },
    { x: 600, y: 550, name: '원자 형성\n(보어 모델)', time: '38만 년' }
  ];

  // 각 단계 그리기
  drawStage0(ctx, stages[0].x, stages[0].y); // 쿼크-글루온 플라즈마
  drawStage1(ctx, stages[1].x, stages[1].y); // 양성자/중성자
  drawStage2(ctx, stages[2].x, stages[2].y); // 핵융합
  drawStage3(ctx, stages[3].x, stages[3].y); // 원자

  // 텍스트 레이블
  stages.forEach((stage, idx) => {
    // 단계 이름
    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 14px Arial';
    ctx.textAlign = 'center';
    const lines = stage.name.split('\n');
    lines.forEach((line, i) => {
      ctx.fillText(line, stage.x, stage.y + 95 + i * 16);
    });

    // 시간
    ctx.fillStyle = '#cccccc';
    ctx.font = '12px Arial';
    ctx.fillText(stage.time, stage.x, stage.y + 130);
  });

  return canvas;
}

// 1️⃣ 쿼크-글루온 플라즈마
function drawStage0(ctx, x, y) {
  const centerX = x;
  const centerY = y;

  // 중앙 뭉치 - 컬러풀한 입자들
  drawColorfulCore(ctx, centerX, centerY, 15, 200);

  // 3개 궤도
  drawOrbit(ctx, centerX, centerY, 40, '#ff4444', true); // 빨강
  drawOrbit(ctx, centerX, centerY, 65, '#4488ff', true); // 파랑
  drawOrbit(ctx, centerX, centerY, 90, '#44ff44', true); // 초록
}

// 2️⃣ 양성자/중성자 형성
function drawStage1(ctx, x, y) {
  const centerX = x;
  const centerY = y;

  // 더 큰 중앙 핵
  drawColorfulCore(ctx, centerX, centerY, 22, 300);

  // 2개 궤도 (더 가까움)
  drawOrbit(ctx, centerX, centerY, 45, '#ffaa88', false); // 연빨강
  drawOrbit(ctx, centerX, centerY, 70, '#88bbff', false); // 연파랑
}

// 3️⃣ 핵융합 → 원자핵 형성
function drawStage2(ctx, x, y) {
  const centerX = x;
  const centerY = y;

  // 더 큰 핵 (여러 색상)
  drawNucleus(ctx, centerX, centerY, 30, 400);

  // 1개 궤도 (거의 중심)
  drawOrbit(ctx, centerX, centerY, 45, '#ffcc77', false);
}

// 4️⃣ 원자 형성 (보어 모델)
function drawStage3(ctx, x, y) {
  const centerX = x;
  const centerY = y;

  // 매우 작은 핵 (중앙)
  ctx.fillStyle = '#ffff44';
  ctx.beginPath();
  ctx.arc(centerX, centerY, 4, 0, Math.PI * 2);
  ctx.fill();

  // 3개 전자 껍질 원형
  ctx.strokeStyle = '#44bbff';
  ctx.lineWidth = 1;

  // K-shell
  ctx.beginPath();
  ctx.arc(centerX, centerY, 30, 0, Math.PI * 2);
  ctx.stroke();

  // L-shell
  ctx.beginPath();
  ctx.arc(centerX, centerY, 55, 0, Math.PI * 2);
  ctx.stroke();

  // M-shell
  ctx.beginPath();
  ctx.arc(centerX, centerY, 80, 0, Math.PI * 2);
  ctx.stroke();

  // 전자 입자들
  drawElectrons(ctx, centerX, centerY, 30, 8, '#44bbff');
  drawElectrons(ctx, centerX, centerY, 55, 12, '#66ccff');
  drawElectrons(ctx, centerX, centerY, 80, 10, '#88ddff');
}

// 중앙 뭉치 - 컬러풀한 입자들
function drawColorfulCore(ctx, x, y, radius, numParticles) {
  const colors = ['#ff5555', '#5588ff', '#55ff55', '#ffff55'];

  for (let i = 0; i < numParticles; i++) {
    const angle = (i / numParticles) * Math.PI * 2 + Math.random() * 0.3;
    const r = Math.random() * radius;
    const px = x + Math.cos(angle) * r;
    const py = y + Math.sin(angle) * r;

    const color = colors[Math.floor(Math.random() * colors.length)];
    ctx.fillStyle = color;
    ctx.globalAlpha = 0.7;
    ctx.beginPath();
    ctx.arc(px, py, 1.5, 0, Math.PI * 2);
    ctx.fill();
  }

  ctx.globalAlpha = 1.0;
}

// 원자핵 (다양한 색상)
function drawNucleus(ctx, x, y, radius, numParticles) {
  const nucleusColors = ['#22ffff', '#55ff55', '#ffff55'];

  for (let i = 0; i < numParticles; i++) {
    const angle = (i / numParticles) * Math.PI * 2 + Math.random() * 0.2;
    const r = Math.random() * radius;
    const px = x + Math.cos(angle) * r;
    const py = y + Math.sin(angle) * r;

    const color = nucleusColors[i % 3];
    ctx.fillStyle = color;
    ctx.globalAlpha = 0.8;
    ctx.beginPath();
    ctx.arc(px, py, 1.2, 0, Math.PI * 2);
    ctx.fill();
  }

  ctx.globalAlpha = 1.0;
}

// 궤도 그리기
function drawOrbit(ctx, x, y, radius, color, dashed = false) {
  ctx.strokeStyle = color;
  ctx.lineWidth = 1;
  ctx.globalAlpha = 0.6;

  if (dashed) {
    ctx.setLineDash([5, 5]);
  }

  ctx.beginPath();
  ctx.arc(x, y, radius, 0, Math.PI * 2);
  ctx.stroke();

  ctx.setLineDash([]);
  ctx.globalAlpha = 1.0;

  // 궤도 입자들
  const numParticles = Math.floor(radius * 2.5);
  for (let i = 0; i < numParticles; i++) {
    const angle = (i / numParticles) * Math.PI * 2;
    const px = x + Math.cos(angle) * radius;
    const py = y + Math.sin(angle) * radius;

    ctx.fillStyle = color;
    ctx.globalAlpha = 0.8;
    ctx.beginPath();
    ctx.arc(px, py, 0.8, 0, Math.PI * 2);
    ctx.fill();
  }

  ctx.globalAlpha = 1.0;
}

// 전자 그리기
function drawElectrons(ctx, x, y, radius, count, color) {
  for (let i = 0; i < count; i++) {
    const angle = (i / count) * Math.PI * 2;
    const px = x + Math.cos(angle) * radius;
    const py = y + Math.sin(angle) * radius;

    ctx.fillStyle = color;
    ctx.globalAlpha = 0.9;
    ctx.beginPath();
    ctx.arc(px, py, 1.2, 0, Math.PI * 2);
    ctx.fill();
  }

  ctx.globalAlpha = 1.0;
}

// 애니메이션 함수 - 실시간 업데이트용
export function updateEducationalBigBangCanvas(canvas, time) {
  const ctx = canvas.getContext('2d');

  // 배경
  ctx.fillStyle = '#000000';
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  // 단계별 위치
  const stages = [
    { x: 200, y: 200, name: '쿼크-글루온\n플라즈마', time: '10⁻¹² 초' },
    { x: 600, y: 200, name: '양성자/중성자\n형성', time: '10⁻⁶ 초' },
    { x: 200, y: 550, name: '핵융합\n원자핵 형성', time: '1-3 분' },
    { x: 600, y: 550, name: '원자 형성\n(보어 모델)', time: '38만 년' }
  ];

  // 각 단계 업데이트
  updateStage0(ctx, stages[0].x, stages[0].y, time);
  updateStage1(ctx, stages[1].x, stages[1].y, time);
  updateStage2(ctx, stages[2].x, stages[2].y, time);
  updateStage3(ctx, stages[3].x, stages[3].y, time);

  // 텍스트 레이블
  stages.forEach((stage) => {
    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 14px Arial';
    ctx.textAlign = 'center';
    const lines = stage.name.split('\n');
    lines.forEach((line, i) => {
      ctx.fillText(line, stage.x, stage.y + 95 + i * 16);
    });

    ctx.fillStyle = '#cccccc';
    ctx.font = '12px Arial';
    ctx.fillText(stage.time, stage.x, stage.y + 130);
  });
}

// 동적 업데이트 함수들
function updateStage0(ctx, x, y, time) {
  drawColorfulCore(ctx, x, y, 15, 200);

  // 회전 궤도
  drawRotatingOrbit(ctx, x, y, 40, '#ff4444', time, 0);
  drawRotatingOrbit(ctx, x, y, 65, '#4488ff', time, 1);
  drawRotatingOrbit(ctx, x, y, 90, '#44ff44', time, 2);
}

function updateStage1(ctx, x, y, time) {
  drawColorfulCore(ctx, x, y, 22, 300);

  drawRotatingOrbit(ctx, x, y, 45, '#ffaa88', time, 0);
  drawRotatingOrbit(ctx, x, y, 70, '#88bbff', time, 1);
}

function updateStage2(ctx, x, y, time) {
  drawNucleus(ctx, x, y, 30, 400);
  drawRotatingOrbit(ctx, x, y, 45, '#ffcc77', time, 0);
}

function updateStage3(ctx, x, y, time) {
  // 핵
  ctx.fillStyle = '#ffff44';
  ctx.beginPath();
  ctx.arc(x, y, 4, 0, Math.PI * 2);
  ctx.fill();

  // 껍질
  ctx.strokeStyle = '#44bbff';
  ctx.lineWidth = 1;

  for (let shell = 0; shell < 3; shell++) {
    const radius = 30 + shell * 25;
    ctx.beginPath();
    ctx.arc(x, y, radius, 0, Math.PI * 2);
    ctx.stroke();
  }

  // 회전하는 전자
  drawRotatingElectrons(ctx, x, y, 30, 8, '#44bbff', time, 0);
  drawRotatingElectrons(ctx, x, y, 55, 12, '#66ccff', time, 1);
  drawRotatingElectrons(ctx, x, y, 80, 10, '#88ddff', time, 2);
}

// 회전 궤도
function drawRotatingOrbit(ctx, x, y, radius, color, time, orbitIdx) {
  ctx.strokeStyle = color;
  ctx.lineWidth = 1;
  ctx.globalAlpha = 0.6;
  ctx.setLineDash([5, 5]);

  ctx.beginPath();
  ctx.arc(x, y, radius, 0, Math.PI * 2);
  ctx.stroke();

  ctx.setLineDash([]);
  ctx.globalAlpha = 1.0;

  // 회전하는 입자들
  const numParticles = Math.floor(radius * 2.5);
  const rotationSpeed = (orbitIdx + 1) * 0.5;

  for (let i = 0; i < numParticles; i++) {
    const baseAngle = (i / numParticles) * Math.PI * 2;
    const angle = baseAngle + time * rotationSpeed;
    const px = x + Math.cos(angle) * radius;
    const py = y + Math.sin(angle) * radius;

    ctx.fillStyle = color;
    ctx.globalAlpha = 0.8;
    ctx.beginPath();
    ctx.arc(px, py, 0.8, 0, Math.PI * 2);
    ctx.fill();
  }

  ctx.globalAlpha = 1.0;
}

// 회전하는 전자
function drawRotatingElectrons(ctx, x, y, radius, count, color, time, shellIdx) {
  const rotationSpeed = (shellIdx + 1) * 0.3;

  for (let i = 0; i < count; i++) {
    const baseAngle = (i / count) * Math.PI * 2;
    const angle = baseAngle + time * rotationSpeed;
    const px = x + Math.cos(angle) * radius;
    const py = y + Math.sin(angle) * radius;

    ctx.fillStyle = color;
    ctx.globalAlpha = 0.9;
    ctx.beginPath();
    ctx.arc(px, py, 1.2, 0, Math.PI * 2);
    ctx.fill();
  }

  ctx.globalAlpha = 1.0;
}

// 단계 정보
export const educationalBigBangStages = [
  {
    id: 0,
    name: "쿼크-글루온 플라즈마",
    timeRange: "10⁻¹² 초",
    description: "우주 극초기 - 극도로 뜨거운 상태"
  },
  {
    id: 1,
    name: "양성자/중성자 형성",
    timeRange: "10⁻⁶ 초",
    description: "쿼크들이 결합하기 시작"
  },
  {
    id: 2,
    name: "핵융합 → 원자핵",
    timeRange: "1-3 분",
    description: "헬륨-4, 리튬 등 형성"
  },
  {
    id: 3,
    name: "원자 형성",
    timeRange: "38만 년",
    description: "전자가 원자핵 주변을 돌기 시작"
  }
];
